import React, { useState } from 'react';
// import logo from '../Assets/Car24 logo.png';
import './ComingSoon.css';
import logo from 'client/src/Assets\Car 24 logo.png';

const ComingSoon = () => {
  const [email, setEmail] = useState('');

  const handleNotify = () => {
    if (email) {
      alert(`Thank you! We will notify you at ${email}`);
      setEmail('');
    } else {
      alert('Please enter your email address');
    }
  };

  return (
    <div className="page">
      <div className="container">

        {/* Logo */}
        <img src={logo} alt="Car24 Logo" className="logo" />

        <h1>Premium Self Drive Rentals</h1>

        <p className="subtitle">
          Book your ride. Drive anywhere. No limits.
        </p>

        <div className="features">
          <div>• Unlimited Mileage</div>
          <div>• 24/7 Pickup</div>
          <div>• Fully Insured</div>
          <div>• Electric & Hybrid Fleet</div>
        </div>

        <div className="notify-form">
          <input
            type="email"
            placeholder="Enter your email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
          <button onClick={handleNotify}>Notify Me</button>
        </div>

        <p className="coming-text">Launching Soon</p>

      </div>
    </div>
  );
};

export default ComingSoon;
